mapper.select:
SELECT TGRM_NM_ENG AS tgrmNmEng, TGRM_NM_KOR AS tgrmNmKor, MSK_PTTRN AS mskPttrn, CHG_DTM AS chgDtm FROM mhdb.TB_TGRM_MASK WHERE 1=1
AND TGRM_NM_ENG ILIKE #{tgrmNmEng}
ORDER BY CHG_DTM

mapper.update:
UPDATE mhdb.TB_TGRM_MASK
SET
	MSK_PTTRN = #{msk_pttrn},
	TGRM_NM_KOR = #{tgrm_nm_kor}
WHERE 1=1
	AND TGRM_NM_ENG = #{tgrm_nm_eng}

mapper.delete:
DELETE FROM mhdb.TB_TGRM_MASK
WHERE 1=1
	AND TGRM_NM_ENG = #{tgrmNmEng}
